import { Request, Response, NextFunction } from 'express';
import { UserService } from './user.service';
import { UserDto } from './user.dto';
import { validateCreateUser, validateLoginUser } from './user.validator';
import { AppError } from '../../utils/app-error';

export class UserController {
  constructor(private userService: UserService) {}

  public async register(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const data = validateCreateUser(req.body);
      const userDto: UserDto = {
        username: data.username,
        email: data.email,
        password: data.password
      };
      const result = await this.userService.register(userDto);
      res.status(201).json({ success: true, data: result });
    } catch (error) {
      next(new AppError('USER_REGISTER_FAILED', error.message));
    }
  }

  public async login(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const data = validateLoginUser(req.body);
      const token = await this.userService.login(data.username, data.password);
      res.status(200).json({ success: true, data: { token } });
    } catch (error) {
      next(new AppError('USER_LOGIN_FAILED', error.message));
    }
  }
}

import { UserDto } from './user.dto';
import { UserRepository } from './user.repository';
import * as bcrypt from 'bcrypt';
import * as jwt from 'jsonwebtoken';
import { AppConfig } from '../../config/env';
import { AppError } from '../../utils/app-error';

export class UserService {
  constructor(private userRepository: UserRepository) {}

  public async register(userDto: UserDto): Promise<any> {
    const passwordHash = await bcrypt.hash(userDto.password, 10);
    const user = await this.userRepository.create({ ...userDto, passwordHash });
    return { id: user.id, username: user.username, email: user.email };
  }

  public async login(username: string, password: string): Promise<string> {
    const user = await this.userRepository.findByUsername(username);
    if (!user) {
      throw new AppError('USER_NOT_FOUND', 'User does not exist');
    }
    const isPasswordValid = await bcrypt.compare(password, user.passwordHash);
    if (!isPasswordValid) {
      throw new AppError('INVALID_PASSWORD', 'Password is incorrect');
    }
    return jwt.sign({ userId: user.id }, AppConfig.JWT_SECRET, { expiresIn: '1h' });
  }
}

import { UserModel } from './user.model';
import { User } from './user.model';

export class UserRepository {
  public async create(user: Partial<User>): Promise<User> {
    return await UserModel.create(user);
  }

  public async findByUsername(username: string): Promise<User | null> {
    return await UserModel.findOne({ username }).exec();
  }
}

import mongoose, { Document, Schema } from 'mongoose';

export interface User extends Document {
  username: string;
  passwordHash: string;
  email: string;
  createdAt: Date;
}

const UserSchema: Schema = new Schema({
  username: { type: String, required: true, unique: true },
  passwordHash: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  createdAt: { type: Date, default: Date.now },
});

export const UserModel = mongoose.model<User>('User', UserSchema);

export interface UserDto {
  username: string;
  password: string;
  email: string;
}

import { z } from 'zod';

const createUserSchema = z.object({
  username: z.string().min(1),
  password: z.string().min(8),
  email: z.string().email(),
});

const loginUserSchema = z.object({
  username: z.string().min(1),
  password: z.string().min(8)
});

export const validateCreateUser = (data: any) => {
  return createUserSchema.parse(data);
};

export const validateLoginUser = (data: any) => {
  return loginUserSchema.parse(data);
};
